import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useNotification } from "../context/NotificationContext";

export default function Sidebar() {
    const { showNotification } = useNotification();
    const location = useLocation();
    const role = localStorage.getItem("role");

    const isActive = (path) => {
        return location.pathname === path ? "active" : "";
    };

    return (
        <div className="sidebar-container">
            <div className="sidebar-header">
                <i className="fa-solid fa-square-parking" style={{ color: "var(--accent-secondary)" }}></i>
                <span>ParkSense</span>
            </div>

            <div className="sidebar-menu">
                <div style={{ fontSize: '0.75rem', fontWeight: 'bold', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '1px', margin: '16px 0 8px 16px' }}>Main Menu</div>

                <Link to="/dashboard" className={`sidebar-link ${isActive('/dashboard')}`}>
                    <i className="fa-solid fa-desktop"></i> Dashboard
                </Link>
                <Link to="/parking" className={`sidebar-link ${isActive('/parking')}`}>
                    <i className="fa-solid fa-map-location-dot"></i> Find Parking
                </Link>
                <Link to="/bookings" className={`sidebar-link ${isActive('/bookings')}`}>
                    <i className="fa-solid fa-ticket"></i> My Reservations
                </Link>

                {role === "admin" && (
                    <>
                        <div style={{ fontSize: '0.75rem', fontWeight: 'bold', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '1px', margin: '24px 0 8px 16px' }}>Admin</div>
                        <Link to="/admin" className={`sidebar-link ${isActive('/admin')}`}>
                            <i className="fa-solid fa-shield-halved"></i> Admin Panel
                        </Link>
                    </>
                )}

                {role === "parkingLotAdmin" && (
                    <>
                        <div style={{ fontSize: '0.75rem', fontWeight: 'bold', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '1px', margin: '24px 0 8px 16px' }}>Lot Admin</div>
                        <Link to="/lot-admin" className={`sidebar-link ${isActive('/lot-admin')}`}>
                            <i className="fa-solid fa-briefcase"></i> Lot Dashboard
                        </Link>
                    </>
                )}

                <div style={{ fontSize: '0.75rem', fontWeight: 'bold', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '1px', margin: '24px 0 8px 16px' }}>Settings</div>
                <Link to="/profile" className={`sidebar-link ${isActive('/profile')}`}>
                    <i className="fa-solid fa-user"></i> Profile
                </Link>
                <Link to="/settings" className={`sidebar-link ${isActive('/settings')}`}>
                    <i className="fa-solid fa-gear"></i> Preferences
                </Link>
            </div>


        </div>
    );
}
